const t = $('Build Newsletter Trigger').first().json;
const DIAC = new RegExp('[' + String.fromCharCode(768) + '-' + String.fromCharCode(879) + ']', 'g');
const norm = function(s){ return String(s || '').normalize('NFD').replace(DIAC, '').toLowerCase(); };
const interests = String(t.interests || '').split(',').map(function(s){ return norm(s).trim(); }).filter(Boolean);
const items = $input.all().map(function(i){ return i.json; });
const seen = new Set();
const all = [];
for (const a of items) {
  const title = String(a.title || '').trim();
  const link = String(a.link || a.guid || '').trim();
  if (!title || !link) continue;
  const key = title.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  let snippet = String(a.contentSnippet || a.content || a.summary || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  if (snippet.length > 220) snippet = snippet.slice(0, 220) + '...';
  let source = '';
  try { source = new URL(link).hostname.replace('www.', ''); } catch(e) {}
  const hay = norm(title + ' ' + snippet);
  const matched = interests.filter(function(kw){ return kw && hay.indexOf(kw) !== -1; });
  all.push({ title: title, link: link, snippet: snippet, source: source, score: matched.length, matched: matched, date: a.isoDate || a.pubDate || '' });
}
all.sort(function(x, y){ return new Date(y.date || 0) - new Date(x.date || 0); });
let LIMIT = parseInt(t.nb_articles, 10);
if (isNaN(LIMIT) || LIMIT < 1) { LIMIT = 6; }
if (LIMIT > 10) { LIMIT = 10; }
let top = [];
if (interests.length) {
  const used = new Set();
  const byInterest = {};
  for (const kw of interests) { byInterest[kw] = all.filter(function(a){ return a.matched.indexOf(kw) !== -1; }); }
  let added = true;
  while (top.length < LIMIT && added) {
    added = false;
    for (const kw of interests) {
      const arr = byInterest[kw];
      while (arr.length) {
        const cand = arr.shift();
        if (!used.has(cand.link)) { used.add(cand.link); top.push(cand); added = true; break; }
      }
      if (top.length >= LIMIT) break;
    }
  }
  if (top.length < LIMIT) { for (const a of all) { if (top.length >= LIMIT) break; if (!used.has(a.link)) { used.add(a.link); top.push(a); } } }
} else { top = all.slice(0, LIMIT); }
const tone = String(t.tone || '').trim();
const fmt = String(t.format || '').trim();
const styleParts = [];
if (tone) { styleParts.push('Adopte un ton ' + tone + '.'); }
if (fmt) { styleParts.push('Respecte cette consigne de format pour chaque resume: ' + fmt + '.'); }
const style_instruction = styleParts.join(' ');
return [{ json: { email: String(t.email || ''), unsubscribe_token: String(t.unsubscribe_token || ''), interests: String(t.interests || ''), tone: tone, format: fmt, style_instruction: style_instruction, articles: top, count: top.length } }];

const d = $input.first().json;
const style = d.style_instruction ? String(d.style_instruction) : 'aucune consigne particuliere, reste neutre et factuel';
const articlesForPrompt = (d.articles || []).map(function(a, i) {
  return { i: i, titre: String(a.title || ''), source: String(a.source || '') };
});
const prompt = 'Tu es un journaliste francophone. Voici des articles au format JSON. Pour chaque article, ecris un resume factuel et neutre en francais de 25 mots maximum, qui apporte du contexte sans repeter le titre mot pour mot. Ecris aussi une courte phrase d intro engageante pour la newsletter.

Consigne de personnalisation a respecter: ' + style + '

Reponds UNIQUEMENT avec un objet JSON valide, sans texte ni balises autour, exactement a ce format: {"intro": "...", "items": [{"i": 0, "resume": "..."}]}

Articles:
' + JSON.stringify(articlesForPrompt);
return [{ json: Object.assign({}, d, { prompt: prompt }) }];

const sel = $('Select & Rank').first().json;
const articles = (sel.articles || []).slice();
let intro = '';
let parsed = null;
try {
  let raw = $json.text;
  if (raw == null) raw = $json.response;
  if (typeof raw !== 'string') raw = JSON.stringify(raw || '');
  // Strip markdown code fences if present
  raw = raw.replace(/^```[\w]*\n?/m, '').replace(/\n?```$/m, '').trim();
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) parsed = JSON.parse(m[0]);
} catch(e) { parsed = null; }
if (parsed) {
  if (parsed.intro) intro = String(parsed.intro);
  const list = Array.isArray(parsed.items) ? parsed.items : [];
  for (const it of list) {
    const idx = Number(it.i);
    if (!isNaN(idx) && articles[idx] && it.resume) {
      articles[idx] = Object.assign({}, articles[idx], { snippet: String(it.resume) });
    }
  }
}
return [{ json: { email: sel.email, unsubscribe_token: sel.unsubscribe_token, interests: sel.interests, intro: intro, articles: articles, count: articles.length } }];

const d = $input.first().json;
const articles = d.articles || [];
const intro = d.intro ? String(d.intro) : '';
const today = new Date().toLocaleDateString('fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
let items = '';
if (!articles.length) {
  items = '<tr><td style="color:#475569;font-size:15px;">Aucune actualit\u00e9 pertinente pour vos centres d\'int\u00e9r\u00eat aujourd\'hui. Revenez demain !</td></tr>';
} else {
  for (let i = 0; i < articles.length; i++) {
    const a = articles[i];
    const src = a.source ? '<span style="color:#94a3b8;font-size:12px;"> &middot; ' + a.source + '</span>' : '';
    const sn = a.snippet ? '<p style="margin:6px 0 0;color:#475569;font-size:14px;line-height:1.55;">' + a.snippet + '</p>' : '';
    items += '<tr><td style="padding:0 0 18px 0;border-bottom:1px solid #eef2f7;"><a href="' + a.link + '" style="color:#1d4ed8;text-decoration:none;font-size:16px;font-weight:600;line-height:1.4;">' + (i + 1) + '. ' + a.title + '</a>' + src + sn + '</td></tr><tr><td style="height:16px;"></td></tr>';
  }
}
const introHtml = intro ? '<p style="margin:0 0 18px 0;color:#334155;font-size:15px;line-height:1.6;font-style:italic;">' + intro + '</p>' : '';
const html = '<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"></head><body style="margin:0;padding:24px 12px;background:#f1f5f9;font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;"><table role="presentation" align="center" width="600" style="max-width:600px;width:100%;border-collapse:collapse;background:#ffffff;border-radius:16px;overflow:hidden;"><tr><td style="background:#1d4ed8;padding:26px 30px;"><h1 style="margin:0;color:#ffffff;font-size:23px;">Persona</h1><p style="margin:6px 0 0;color:#dbeafe;font-size:13px;">Votre actualit\u00e9 du ' + today + '</p></td></tr><tr><td style="padding:26px 30px;">' + introHtml + '<table role="presentation" width="100%" style="border-collapse:collapse;">' + items + '</table></td></tr><tr><td style="padding:16px 30px;background:#f8fafc;border-top:1px solid #eef2f7;color:#94a3b8;font-size:12px;line-height:1.6;">Vous recevez cet email car vous \u00eates inscrit \u00e0 Persona avec ' + d.email + '.<br>Pour vous d\u00e9sabonner, \u00e9crivez \u00ab\u00a0d\u00e9sabonne-moi\u00a0\u00bb dans le chatbot Persona.</td></tr></table></body></html>';
const subject = articles.length ? ('\uD83D\uDDDE\uFE0F Votre actu Persona \u2014 ' + articles.length + ' \u00e0 la une') : 'Persona \u2014 pas d\'actu aujourd\'hui';
return [{ json: { email: d.email, subject: subject, body: html } }];
